export const mockCities: City[] = cityData();
function cityData(): City[] {
  const cities: City[] = [];
  const stateIds: Record<string, string> = {};
  for (const s of mockStates) { stateIds[s.name] = s.id; }
  const cityList: [string, string, number, string, string[], string][] = [
    ['Mumbai', 'Maharashtra', 20650000, 'The financial capital of India, Mumbai is a bustling metropolis with colonial architecture, Bollywood glamour, and vibrant street life.', ['Gateway of India', 'Marine Drive', 'Elephanta Caves'], 'Mumbai is well-connected by air, rail, and road. Chhatrapati Shivaji Terminus is a UNESCO World Heritage site.'],
    ['Delhi', 'Delhi', 19000000, 'The national capital, Delhi is a city where ancient history meets modernity with its Mughal monuments and bustling markets.', ['Red Fort', 'Qutub Minar', 'India Gate', 'Akshardham Temple'], 'Delhi has an extensive metro network. Indira Gandhi International Airport connects to all major cities.'],
    ['Bengaluru', 'Karnataka', 12400000, 'The Silicon Valley of India, Bengaluru is known for its pleasant climate, parks, and vibrant tech culture.', ['Lalbagh Garden', 'Cubbon Park', 'Vidhana Soudha', 'MG Road'], 'Bengaluru has Kempegowda International Airport and an extensive bus/metro network.'],
    ['Hyderabad', 'Telangana', 10200000, 'The City of Pearls, Hyderabad blends ancient history with modern IT hubs and legendary cuisine.', ['Charminar', 'Golconda Fort', 'Hussain Sagar', 'Ramoji Film City'], 'Rajiv Gandhi International Airport connects globally. The Hyderabad Metro serves the city.'],
    ['Chennai', 'Tamil Nadu', 11500000, 'The cultural capital of South India, Chennai is known for its temples, classical dance, and Marina Beach.', ['Marina Beach', 'Kapaleeshwarar Temple', 'Fort St. George', 'Mylapore'], 'Chennai International Airport is a major hub. The city has an extensive suburban rail network.'],
    ['Kolkata', 'West Bengal', 14500000, 'The cultural capital of India, Kolkata is known for its colonial architecture, literary heritage, and Durga Puja.', ['Victoria Memorial', 'Howrah Bridge', 'Kalighat Temple', 'Indian Museum'], 'Netaji Subhas Chandra Bose International Airport serves the city. The metro is India oldest.'],
    ['Jaipur', 'Rajasthan', 4050000, 'The Pink City, Jaipur is famous for its majestic palaces, vibrant bazaars, and Rajasthani cuisine.', ['Hawa Mahal', 'Amber Fort', 'City Palace', 'Jantar Mantar', 'Jaipur Bazaar'], 'Jaipur International Airport connects major cities. The city is part of the Golden Triangle circuit.'],
    ['Lucknow', 'Uttar Pradesh', 3820000, 'The City of Nawabs, Lucknow is known for its refined cuisine, etiquette, and magnificent Mughal architecture.', ['Bara Imambara', 'Chota Imambara', 'Rumi Darwaza', 'Hussainabad Clock Tower'], 'Chaudhary Charan Singh International Airport and Lucknow Railway Station serve the city.'],
    ['Ahmedabad', 'Gujarat', 8200000, 'The commercial hub of Gujarat, Ahmedabad is known for its Sabarmati Ashram and vibrant textile industry.', ['Sabarmati Ashram', 'Kankaria Lake', 'Adalaj Stepwell', 'Sidi Saiyyed Mosque'], 'Sardar Vallabhbhai Patel International Airport and Ahmedabad Junction serve the city.'],
    ['Pune', 'Maharashtra', 6500000, 'The cultural capital of Maharashtra, Pune is known for its educational institutions and pleasant climate.', ['Shaniwar Wada', 'Aga Khan Palace', 'Sinhagad Fort', 'Dagdusheth Temple'], 'Pune International Airport connects major cities. The city has a growing metro system.'],
    ['Chandigarh', 'Chandigarh', 1200000, "India first planned city, Chandigarh is known for Le Corbusier modernist architecture.", ['Rock Garden', 'Sukhna Lake', 'Capitol Complex', 'Rose Garden'], 'Chandigarh Airport connects major cities. The city is well-planned with wide roads.'],
    ['Varanasi', 'Uttar Pradesh', 3700000, 'The spiritual capital of India, Varanasi is one of the oldest continuously inhabited cities in the world.', ['Kashi Vishwanath Temple', 'Ganga Aarti', 'Sarnath', 'Assi Ghat'], 'Lal Bahadur Shastri International Airport and Varanasi Junction Railway Station serve the city.'],
    ['Agra', 'Uttar Pradesh', 1900000, 'Home to the iconic Taj Mahal, Agra is a city of Mughal heritage and exquisite craftsmanship.', ['Taj Mahal', 'Agra Fort', 'Fatehpur Sikri', 'Mehtab Bagh'], 'Agra is well-connected by rail and road. The nearest airport is in Delhi.'],
    ['Udaipur', 'Rajasthan', 600000, 'The City of Lakes, Udaipur is known for its romantic palaces and picturesque lakes.', ['City Palace', 'Lake Pichola', 'Jag Mandir', 'Sahelion Ki Bari', 'Fateh Sagar Lake'], 'Maharana Pratap Airport connects major cities. Udaipur is a popular wedding destination.'],
    ['Amritsar', 'Punjab', 2000000, 'The spiritual heart of Sikhism, Amritsar is home to the magnificent Golden Temple.', ['Golden Temple', 'Jallianwala Bagh', 'Wagah Border', 'Partition Museum'], 'Sri Guru Ram Dass Jee International Airport serves the city.'],
  ];
  for (const [name, st, pop, desc, places, travel] of cityList) {
    const sid = stateIds[st];
    if (!sid) continue;
    const cityPlaces = places || [];
    cities.push({
      id: id(), stateId: sid, districtId: '', name, population: pop,
      description: desc, famousPlaces: cityPlaces,
      touristAttractions: cityPlaces, nearbyDestinations: [],
      localFoods: [], travelInfo: travel,
      coordinates: { lat: 20 + Math.random() * 15, lng: 72 + Math.random() * 15 },
      imageUrl: 'https://images.unsplash.com/photo-1599661046289-e31897846e41?w=800',
    });
  }
  return cities;
}

const allSearchResults: SearchResult[] = [];

export function buildSearchIndex(): SearchResult[] {
  if (allSearchResults.length > 0) return allSearchResults;
  for (const s of mockStates) {
    allSearchResults.push({ type: 'State', id: s.id, title: s.name, description: s.capital ? `Capital: ${s.capital}` : '', imageUrl: s.imageUrl, url: `/states/${s.name.toLowerCase().replace(/\s+/g, '-')}`, relevance: 10 });
  }
  for (const m of mockMonuments) {
    allSearchResults.push({ type: 'Monument', id: m.id, title: m.name, description: m.description.substring(0, 100), imageUrl: m.imageUrl, url: `/monuments/${m.name.toLowerCase().replace(/\s+/g, '-')}`, relevance: 8 });
  }
  for (const f of mockFoods) {
    allSearchResults.push({ type: 'Food', id: f.id, title: f.name, description: f.description.substring(0, 100), imageUrl: f.imageUrl, url: `/food/${f.name.toLowerCase().replace(/\s+/g, '-')}`, relevance: 6 });
  }
  for (const fe of mockFestivals) {
    allSearchResults.push({ type: 'Festival', id: fe.id, title: fe.name, description: fe.description.substring(0, 100), imageUrl: fe.imageUrl, url: `/festivals/${fe.name.toLowerCase().replace(/\s+/g, '-')}`, relevance: 7 });
  }
  for (const e of mockEvents) {
    allSearchResults.push({ type: 'Historical Event', id: e.id, title: e.title, description: e.description.substring(0, 100), imageUrl: e.imageUrl, url: `/history/${e.id}`, relevance: 5 });
  }
  for (const c of mockCities) {
    allSearchResults.push({ type: 'City', id: c.id, title: c.name, description: c.description.substring(0, 100), imageUrl: c.imageUrl, url: `/cities/${c.name.toLowerCase().replace(/\s+/g, '-')}`, relevance: 9 });
  }
  return allSearchResults;
}

export function getStateIdByName(name: string): string | undefined {
  return stateByName[name]?.id;
}


